}
.column:last-child {
  margin-right: 0;
}

img {
  max-width: 100%; /* Image will scale down if larger than its container */
  height: auto;    /* Maintain aspect ratio */
  display: block;  /* Remove extra space below image */
}

/* Default styles for smaller screens (mobile-first) */
body {
  font-size: 16px;
}

.navigation {
  display: block; /* Stacked navigation on small screens */
}

/* Styles for screens wider than 768px (e.g., tablets and desktops) */
@media screen and (min-width: 768px) {
  body {
    font-size: 18px;
  }

  .navigation {
    display: flex; /* Horizontal navigation on larger screens */
    justify-content: space-around;
  }

  .column {
    width: 48%; /* Two columns on medium screens */
    margin-right: 4%;
  }
  .column:nth-child(2n) {
    margin-right: 0;
  }
}

/* Styles for screens wider than 1024px (e.g., desktops) */
@media screen and (min-width: 1024px) {
  .column {
    width: 31.33%; /* Three columns on large screens */
    margin-right: 2%;
  }
  .column:nth-child(2n) {
    margin-right: 2%; /* Reset for 2n */
  }
  .column:nth-child(3n) {
    margin-right: 0;
  }
}

